mapper.select:
select

from
    rdp_ticket_inst
where
    1=1
     AND owner_uid in #{item}
     AND gmt_create > #{startTime} 
     AND gmt_create < #{endTime} 
     AND id = #{ticketId} 
     AND biz_id = #{ticketBizId} 
     AND ticket_title LIKE concat('%',#{ticketTitleName},'%') 
     AND ticket_status =#{ticketStatus,javaType=com.clougence.clouddm.console.web.dal.enumeration.RdpTicketStatus} 
     AND bind_ds_id in #{item}
    and deleted = false
order by
    gmt_create desc

mapper.update:
update
    rdp_ticket_inst
set
    error_count = #{count}
where
    id = #{ticketId}

update
    rdp_ticket_inst
set
    appro_identity = #{approvalIdentity},approval_url = #{url}
where id = #{ticketId}

update
    rdp_ticket_inst
set
    appro_comment = #{comment}
where id = #{ticketId}

